+			t.Errorf("mergedCount = %d, want 4", mergedCount)
+		}
+
+		// Verify safety check would trigger: >50% vanished AND >5 existed
+		if localCount <= 5 {
+			t.Error("localCount should be > 5 for safety check to apply")
